import { APIGatewayProxyEvent, APIGatewayProxyResult } from 'aws-lambda';
import { connectionsService } from '../services/dynamodb';

export const connect = async (event: APIGatewayProxyEvent): Promise<APIGatewayProxyResult> => {
  const connectionId = event.requestContext.connectionId!;
  
  console.log('WebSocket connect:', connectionId);
  
  try {
    await connectionsService.add(connectionId);
    return { statusCode: 200, body: 'Connected' };
  } catch (error) {
    console.error('Connect error:', error);
    return { statusCode: 500, body: 'Failed to connect' };
  }
};

export const disconnect = async (event: APIGatewayProxyEvent): Promise<APIGatewayProxyResult> => {
  const connectionId = event.requestContext.connectionId!;
  
  console.log('WebSocket disconnect:', connectionId);
  
  try {
    await connectionsService.remove(connectionId);
    return { statusCode: 200, body: 'Disconnected' };
  } catch (error) {
    console.error('Disconnect error:', error);
    return { statusCode: 500, body: 'Failed to disconnect' };
  }
};

export const message = async (event: APIGatewayProxyEvent): Promise<APIGatewayProxyResult> => {
  console.log('WebSocket message:', event.body);
  
  // Handle incoming WebSocket messages if needed
  // For now, just acknowledge receipt
  return { statusCode: 200, body: 'Message received' };
};
